import {Namespace} from 'socket.io';
import {CanvasObject} from '../models/CanvasObject';
import {redis} from '../infra/redis';
import {io} from '../server';
export function registerDesignNamespace(nsp:Namespace){
  nsp.use(authMw);
  nsp.on('connection',socket=>{
    const uid=socket.data.user.id;
    socket.on('canvas:open',async({canvasId},ack)=>{
      await socket.join(`canvas:${canvasId}`);
      const objects=await CanvasObject.find({canvasId,deletedAt:null}).sort({z:1}).lean();
      const locks=await redis.hgetall(`design:locks:${canvasId}`);
      ack({objects,locks});
    });
    socket.on('select:set',({canvasId,objectIds})=>{
      socket.to(`canvas:${canvasId}`).emit('select:peer',{userId:uid,objectIds});
    });
    socket.on('props:patch',async({canvasId,objectId,patch,expectedVersion},ack)=>{
      const r=await CanvasObject.findOneAndUpdate({_id:objectId,version:expectedVersion},{$set:{['props']:patch},$inc:{version:1}},{new:true});
      if(!r)return ack({error:'conflict'});
      socket.to(`canvas:${canvasId}`).emit('props:patched',{objectId,patch,version:r.version,by:uid});
      ack({version:r.version});
    });
    socket.on('obj:add',async({canvasId,object},ack)=>{
      const o=await CanvasObject.create({...object,canvasId});
      io.of('/design').to(`canvas:${canvasId}`).emit('obj:added',o.toObject());
      ack({object:o.toObject()});
    });
    socket.on('obj:delete',async({canvasId,objectId},ack)=>{
      await CanvasObject.updateOne({_id:objectId},{$set:{deletedAt:new Date()}});
      io.of('/design').to(`canvas:${canvasId}`).emit('obj:deleted',{objectId});
      ack({ok:true});
    });
  });
}

