import {useEffect,useState,useCallback} from 'react';
import {io,Socket} from 'socket.io-client';
let sock:Socket|null=null;
function getSock(t:string){if(sock)return sock;sock=io('/design',{auth:{token:t},transports:['websocket']});return sock;}
export function useDesignCanvas(canvasId:string,token:string){
  const [objects,setObjects]=useState<any[]>([]);
  const [peerSelections,setPeer]=useState<Map<string,string[]>>(new Map());
  useEffect(()=>{
    const s=getSock(token);
    const open=()=>s.emit('canvas:open',{canvasId},(r:any)=>setObjects(r.objects));
    const onPeer=(e:any)=>setPeer(p=>{const n=new Map(p);n.set(e.userId,e.objectIds);return n;});
    const onPatch=(e:any)=>setObjects(p=>p.map(o=>o._id===e.objectId?{...o,props:e.patch,version:e.version}:o));
    const onAdd=(o:any)=>setObjects(p=>[...p,o]);
    const onDel=({objectId}:any)=>setObjects(p=>p.filter(o=>o._id!==objectId));
    s.on('connect',open);s.on('select:peer',onPeer);s.on('props:patched',onPatch);s.on('obj:added',onAdd);s.on('obj:deleted',onDel);
    if(s.connected)open();
    return ()=>{s.off('connect',open);s.off('select:peer',onPeer);s.off('props:patched',onPatch);s.off('obj:added',onAdd);s.off('obj:deleted',onDel);};
  },[canvasId,token]);
  const setSelection=useCallback((objectIds:string[])=>getSock(token).emit('select:set',{canvasId,objectIds}),[canvasId,token]);
  const patchProps=useCallback((objectId:string,patch:any,version:number)=>new Promise((res,rej)=>getSock(token).emit('props:patch',{canvasId,objectId,patch,expectedVersion:version},(r:any)=>r.error?rej(r):res(r))),[canvasId,token]);
  return {objects,peerSelections,setSelection,patchProps};
}

