import {Namespace} from 'socket.io';
import {pool} from '../infra/pg';
import {io} from '../server';
export function registerGuildNamespace(nsp:Namespace){
  nsp.use(authMw);
  nsp.on('connection',socket=>{
    const uid=socket.data.user.id;
    socket.on('guild:join',async({guildId,channel},ack)=>{
      const r=await pool.query('SELECT role FROM guild_members WHERE guild_id=$1 AND user_id=$2',[guildId,uid]);
      if(!r.rows[0])return ack({error:'not_member'});
      const role=r.rows[0].role;
      if(channel==='officer'&&role==='member')return ack({error:'no_perm'});
      await socket.join(`guild:${guildId}:${channel}`);
      ack({role});
    });
    socket.on('msg:send',async({guildId,channel,body},ack)=>{
      const mentionMatch=body.match(/@(\w+)/);
      const mentionRole=mentionMatch&&['officers','leaders'].includes(mentionMatch[1])?mentionMatch[1].slice(0,-1):null;
      const ins=await pool.query('INSERT INTO guild_messages(guild_id,channel,sender_id,body,mention_role) VALUES ($1,$2,$3,$4,$5) RETURNING id,ts',[guildId,channel,uid,body,mentionRole]);
      const msg={id:String(ins.rows[0].id),guildId:String(guildId),channel,senderId:String(uid),body,ts:ins.rows[0].ts};
      io.of('/guild').to(`guild:${guildId}:${channel}`).emit('msg:new',msg);
      if(mentionRole){
        const targets=await pool.query('SELECT user_id FROM guild_members WHERE guild_id=$1 AND role=$2',[guildId,mentionRole]);
        for(const t of targets.rows)io.of('/guild').to(`user:${t.user_id}`).emit('mention:officers',msg);
      }
      ack({ok:true});
    });
  });
}

