import {pool} from '../infra/pg';
import {io} from '../server';

export async function pick(draftId:number,userId:number,champion:string){
  const client=await pool.connect();
  try{
    await client.query('BEGIN');
    await client.query('SELECT pg_advisory_xact_lock($1)',[draftId]);
    const d=await client.query('SELECT player_order,pick_idx,picks,bans,status FROM drafts WHERE id=$1 FOR UPDATE',[draftId]);
    if(!d.rows[0]||d.rows[0].status!=='active'){await client.query('ROLLBACK');return {error:'inactive'};}
    const expected=d.rows[0].player_order[d.rows[0].pick_idx];
    if(Number(expected)!==userId){await client.query('ROLLBACK');return {error:'not_your_turn'};}
    if(d.rows[0].picks.find((p:any)=>p.champion===champion)||d.rows[0].bans.includes(champion)){await client.query('ROLLBACK');return {error:'champ_taken'};}
    const newPicks=[...d.rows[0].picks,{userId,champion,at:new Date()}];
    const newIdx=d.rows[0].pick_idx+1;
    const done=newIdx>=d.rows[0].player_order.length;
    await client.query('UPDATE drafts SET picks=$1,pick_idx=$2,pick_started_at=$3,status=$4 WHERE id=$5',[JSON.stringify(newPicks),newIdx,done?null:new Date(),done?'done':'active',draftId]);
    await client.query('COMMIT');
    io.of('/draft').to(`draft:${draftId}`).emit('turn:advance',{draftId:String(draftId),picks:newPicks,pickIdx:newIdx,done});
    return {ok:true};
  }catch(e){await client.query('ROLLBACK');throw e;}finally{client.release();}
}

export function startTicker(){
  setInterval(async()=>{
    const due=await pool.query(`SELECT id,player_order,pick_idx,pick_started_at FROM drafts WHERE status='active' AND pick_started_at IS NOT NULL`);
    for(const d of due.rows){
      const elapsed=Date.now()-new Date(d.pick_started_at).getTime();
      const remaining=Math.max(0,30000-elapsed);
      io.of('/draft').to(`draft:${d.id}`).emit('tick',{draftId:String(d.id),remaining,pickIdx:d.pick_idx});
      if(remaining===0){const userId=d.player_order[d.pick_idx];await pick(Number(d.id),Number(userId),'__auto__');}
    }
  },1000);
}

export function registerDraftNamespace(nsp:any){
  nsp.use(authMw);
  nsp.on('connection',(socket:any)=>{
    socket.on('draft:open',async({draftId}:any,ack:any)=>{const r=await pool.query('SELECT * FROM drafts WHERE id=$1',[draftId]);await socket.join(`draft:${draftId}`);ack({draft:r.rows[0]});});
    socket.on('pick',async({draftId,champion}:any,ack:any)=>{const r=await pick(draftId,socket.data.user.id,champion);ack(r);});
  });
}

