import {useEffect,useState,useCallback} from 'react';
import {io,Socket} from 'socket.io-client';
let sock:Socket|null=null;
function getSock(t:string){if(sock)return sock;sock=io('/draft',{auth:{token:t},transports:['websocket']});return sock;}
export function useDraft(draftId:string,token:string){
  const [draft,setDraft]=useState<any>(null);
  const [remaining,setRemaining]=useState(30);
  useEffect(()=>{
    const s=getSock(token);
    const open=()=>s.emit('draft:open',{draftId},(r:any)=>setDraft(r.draft));
    const onTick=(e:any)=>{if(e.draftId===draftId)setRemaining(Math.ceil(e.remaining/1000));};
    const onAdv=(e:any)=>{if(e.draftId===draftId)setDraft((d:any)=>({...d,picks:e.picks,pick_idx:e.pickIdx,status:e.done?'done':'active'}));};
    s.on('connect',open);s.on('tick',onTick);s.on('turn:advance',onAdv);
    if(s.connected)open();
    return ()=>{s.off('connect',open);s.off('tick',onTick);s.off('turn:advance',onAdv);};
  },[draftId,token]);
  const pick=useCallback((champion:string)=>new Promise((res,rej)=>getSock(token).emit('pick',{draftId,champion},(r:any)=>r.error?rej(r):res(r))),[draftId,token]);
  return {draft,remaining,pick};
}

