import {pool} from '../infra/pg';
import {io} from '../server';

export async function bid(lotId:number,bidderId:number,paddleNo:number|null,amountCents:number,source:'online'|'floor'){
  const client=await pool.connect();
  try{
    await client.query('BEGIN');
    await client.query('SELECT pg_advisory_xact_lock($1)',[lotId]);
    const l=await client.query('SELECT current_bid_cents,status FROM estate_lots WHERE id=$1 FOR UPDATE',[lotId]);
    if(!l.rows[0]||l.rows[0].status!=='live'){await client.query('ROLLBACK');return {error:'not_live'};}
    if(amountCents<=Number(l.rows[0].current_bid_cents)){await client.query('ROLLBACK');return {error:'too_low',current:Number(l.rows[0].current_bid_cents)};}
    await client.query('INSERT INTO estate_bids(lot_id,bidder_id,paddle_no,amount_cents,source) VALUES ($1,$2,$3,$4,$5)',[lotId,bidderId,paddleNo,amountCents,source]);
    await client.query('UPDATE estate_lots SET current_bid_cents=$1,current_bidder_id=$2,current_source=$3 WHERE id=$4',[amountCents,bidderId,source,lotId]);
    await client.query('COMMIT');
    io.of('/estate').to(`lot:${lotId}`).emit('state',{lotId:String(lotId),currentBidCents:amountCents,currentSource:source,paddleNo});
    return {ok:true};
  }catch(e){await client.query('ROLLBACK');throw e;}finally{client.release();}
}

export function registerEstateNamespace(nsp:any){
  nsp.use(authMw);
  nsp.on('connection',(socket:any)=>{
    socket.on('lot:watch',async({lotId}:any,ack:any)=>{await socket.join(`lot:${lotId}`);const r=await pool.query('SELECT * FROM estate_lots WHERE id=$1',[lotId]);ack({lot:r.rows[0]});});
    socket.on('online:bid',async({lotId,amountCents}:any,ack:any)=>{const r=await bid(lotId,socket.data.user.id,null,amountCents,'online');ack(r);});
    socket.on('floor:bid',async({lotId,paddleNo,amountCents}:any,ack:any)=>{if(socket.data.user.role!=='auctioneer')return ack({error:'forbidden'});const r=await bid(lotId,0,paddleNo,amountCents,'floor');ack(r);});
    socket.on('hammer',async({lotId}:any,ack:any)=>{if(socket.data.user.role!=='auctioneer')return ack({error:'forbidden'});await pool.query("UPDATE estate_lots SET status='sold',hammered_at=now() WHERE id=$1",[lotId]);io.of('/estate').to(`lot:${lotId}`).emit('hammered',{lotId:String(lotId)});ack({ok:true});});
  });
}

