import {AudioRoom} from '../models/AudioRoom';
import {io} from '../server';
export function registerAudioNamespace(nsp:any){
  nsp.use(authMw);
  nsp.on('connection',(socket:any)=>{
    const uid=socket.data.user.id;
    socket.on('room:join',async({roomId}:any,ack:any)=>{
      const r=await AudioRoom.findOneAndUpdate({_id:roomId,$expr:{$lt:['$listenerCount','$listenerCap']}},{$inc:{listenerCount:1}},{new:true});
      if(!r)return ack({error:'full_or_no_room'});
      await socket.join(`room:${roomId}`);
      io.of('/audio').to(`room:${roomId}`).emit('state',{room:r});
      ack({room:r});
    });
    socket.on('raise:hand',async({roomId}:any,ack:any)=>{
      const r=await AudioRoom.findOneAndUpdate({_id:roomId,'raiseHandQueue.userId':{$ne:uid}},{$push:{raiseHandQueue:{userId:uid,at:new Date()}}},{new:true});
      if(!r)return ack({error:'already_in_queue'});
      io.of('/audio').to(`room:${roomId}`).emit('state',{room:r});
      ack({ok:true});
    });
    socket.on('promote',async({roomId,targetId}:any,ack:any)=>{
      const r=await AudioRoom.findOne({_id:roomId});if(!r||!r.speakerIds.includes(uid))return ack({error:'forbidden'});
      const upd=await AudioRoom.findOneAndUpdate({_id:roomId,'raiseHandQueue.userId':targetId},{$pull:{raiseHandQueue:{userId:targetId}},$addToSet:{speakerIds:targetId}},{new:true});
      io.of('/audio').to(`room:${roomId}`).emit('state',{room:upd});
      ack({ok:true});
    });
    socket.on('disconnect',async()=>{
      // listener leave; speaker disconnect demotes
    });
  });
}

