import {pool} from '../infra/pg';
import {io} from '../server';
import {enqueueNotification} from '../services/notificationService';
export function registerSheetCommentsNamespace(nsp:any){
  nsp.use(authMw);
  nsp.on('connection',(socket:any)=>{
    const uid=socket.data.user.id;
    socket.on('sheet:open',async({sheetId}:any,ack:any)=>{
      await socket.join(`sheet:${sheetId}`);
      const r=await pool.query('SELECT * FROM sheet_comments WHERE sheet_id=$1 AND resolved=false ORDER BY id',[sheetId]);
      ack({comments:r.rows});
    });
    socket.on('comment:add',async({sheetId,ref,body}:any,ack:any)=>{
      const r=await pool.query('INSERT INTO sheet_comments(sheet_id,ref,author_id,body) VALUES ($1,$2,$3,$4) RETURNING id,created_at',[sheetId,ref,uid,body]);
      const c={id:String(r.rows[0].id),sheet_id:String(sheetId),ref,author_id:String(uid),body,resolved:false,created_at:r.rows[0].created_at};
      io.of('/sheetcomments').to(`sheet:${sheetId}`).emit('comment:new',c);
      for(const m of (body.match(/@(\d+)/g)||[])){const mid=m.slice(1);await enqueueNotification(mid,{type:'cell_mention',targetType:'comment',targetId:c.id,actorId:String(uid),body:`Mentioned in cell ${ref}`});}
      ack({comment:c});
    });
    socket.on('comment:reply',async({sheetId,parentId,body}:any,ack:any)=>{
      const r=await pool.query('INSERT INTO sheet_comments(sheet_id,ref,thread_root_id,author_id,body) SELECT $1,ref,$2,$3,$4 FROM sheet_comments WHERE id=$2 RETURNING id,ref,created_at',[sheetId,parentId,uid,body]);
      if(r.rowCount===0)return ack({error:'no_parent'});
      io.of('/sheetcomments').to(`sheet:${sheetId}`).emit('comment:reply',{id:String(r.rows[0].id),parentId:String(parentId),body,authorId:String(uid),createdAt:r.rows[0].created_at});
      ack({ok:true});
    });
    socket.on('comment:resolve',async({sheetId,threadRootId}:any,ack:any)=>{
      await pool.query('UPDATE sheet_comments SET resolved=true WHERE sheet_id=$1 AND (id=$2 OR thread_root_id=$2)',[sheetId,threadRootId]);
      io.of('/sheetcomments').to(`sheet:${sheetId}`).emit('comment:resolved',{threadRootId:String(threadRootId)});
      ack({ok:true});
    });
  });
}

