import {pool} from '../infra/pg';
import {io} from '../server';
import {Namespace} from 'socket.io';
export function registerWatchNamespace(nsp:Namespace){
  nsp.use(authMw);
  nsp.on('connection',(socket:any)=>{
    const uid=socket.data.user.id;
    socket.join(`user:${uid}`);
    socket.on('watch:status',async({deviceId,batteryPct,bleConnected,dnd}:any)=>{
      await pool.query('INSERT INTO watch_devices(user_id,device_id,battery_pct,ble_connected,dnd) VALUES ($1,$2,$3,$4,$5) ON CONFLICT (device_id) DO UPDATE SET battery_pct=EXCLUDED.battery_pct,ble_connected=EXCLUDED.ble_connected,dnd=EXCLUDED.dnd',[uid,deviceId,batteryPct,bleConnected,dnd]);
    });
    socket.on('read:sync',async({notifId}:any)=>{await pool.query('UPDATE watch_deliveries SET read_at=now() WHERE notif_id=$1 AND user_id=$2',[notifId,uid]);});
  });
}
export async function maybeRelayToWatch(userId:string,notif:any){
  const f=await pool.query('SELECT types,min_severity FROM watch_filters WHERE user_id=$1',[userId]);
  const d=await pool.query('SELECT device_id,battery_pct,ble_connected,dnd FROM watch_devices WHERE user_id=$1',[userId]);
  if(!f.rows[0]||!d.rows[0])return;
  const filt=f.rows[0];const dev=d.rows[0];
  if(!dev.ble_connected||dev.dnd||dev.battery_pct<10)return;
  if(filt.types&&!filt.types.includes(notif.type))return;
  // assume severity ord: low<normal<urgent
  const ord:Record<string,number>={low:0,normal:1,urgent:2};
  if(ord[notif.severity||'normal']<ord[filt.min_severity||'low'])return;
  io.of('/watch').to(`user:${userId}`).emit('notif:relay',{notifId:notif.id,title:notif.title?.slice(0,40),body:notif.body?.slice(0,80)});
  await pool.query('INSERT INTO watch_deliveries(user_id,device_id,notif_id,delivered_at) VALUES ($1,$2,$3,now())',[userId,dev.device_id,notif.id]);
}

