import crypto from 'crypto';
export async function proposeCommand(plcId:number,tag:string,value:number,userId:number){
  const client=await pool.connect();
  try{await client.query('BEGIN');await client.query('SELECT pg_advisory_xact_lock($1)',[plcId]);
    const prev=await client.query('SELECT row_hash FROM plc_commands WHERE plc_id=$1 ORDER BY id DESC LIMIT 1',[plcId]);
    const prevHash=prev.rows[0]?.row_hash??Buffer.alloc(32);
    const payload=JSON.stringify({plcId,tag,value,userId,at:Date.now()});
    const rowHash=crypto.createHash('sha256').update(Buffer.concat([Buffer.from(prevHash),Buffer.from(payload)])).digest();
    const r=await client.query('INSERT INTO plc_commands(plc_id,tag,target_value,issued_by,prev_hash,row_hash) VALUES ($1,$2,$3,$4,$5,$6) RETURNING id',[plcId,tag,value,userId,prevHash,rowHash]);
