    io.of('/scada').to(`plc:${plcId}`).emit('cmd:proposed',{commandId:String(r.rows[0].id),plcId:String(plcId),tag,value,by:userId});
    return {commandId:String(r.rows[0].id)};
  }catch(e){await client.query('ROLLBACK');throw e;}finally{client.release();}
}
