import {useEffect,useState,useCallback} from 'react';
import {io,Socket} from 'socket.io-client';
let sock:Socket|null=null;
function getSock(t:string){if(sock)return sock;sock=io('/scada',{auth:{token:t},transports:['websocket']});return sock;}
export function usePlc(plcId:string,token:string){
  const [tags,setTags]=useState<Map<string,number>>(new Map());
  const [pending,setPending]=useState<any[]>([]);
  useEffect(()=>{
    const s=getSock(token);
    const sub=()=>s.emit('plc:subscribe',{plcId},(r:any)=>setTags(new Map(r.current.map((t:any)=>[t.tag,Number(t.value)]))));
    const onSample=(s2:any)=>{if(s2.plcId===plcId)setTags(p=>{const n=new Map(p);n.set(s2.tag,s2.value);return n;});};
    const onProp=(c:any)=>{if(c.plcId===plcId)setPending(p=>[...p,c]);};
    const onExec=({commandId}:any)=>setPending(p=>p.filter(c=>c.commandId!==commandId));
    s.on('connect',sub);s.on('sample',onSample);s.on('cmd:proposed',onProp);s.on('cmd:executed',onExec);
    if(s.connected)sub();
    return ()=>{s.off('connect',sub);s.off('sample',onSample);s.off('cmd:proposed',onProp);s.off('cmd:executed',onExec);};
  },[plcId,token]);
  const propose=useCallback((tag:string,value:number)=>new Promise((res,rej)=>getSock(token).emit('cmd:propose',{plcId,tag,value},(r:any)=>r.error?rej(r):res(r))),[plcId,token]);
  const confirm=useCallback((commandId:string)=>new Promise((res,rej)=>getSock(token).emit('cmd:confirm',{commandId},(r:any)=>r.error?rej(r):res(r))),[token]);
  return {tags,pending,propose,confirm};
}

