      ack({sessionId:String(r.rows[0].id)});
    });
    socket.on('control:revoke',async({sessionId}:any,ack:any)=>{
      const r=await pool.query(`UPDATE remote_sessions SET ended_at=now(),reason='revoked' WHERE id=$1 AND host_id=$2 AND ended_at IS NULL RETURNING call_id`,[sessionId,uid]);
      if(r.rowCount===0)return ack({error:'no_session'});
      io.of('/remote').to(`call:${r.rows[0].call_id}`).emit('session:state',{type:'revoked',sessionId});
      ack({ok:true});
    });
    socket.on('input:audit',async({sessionId,eventType,payload}:any)=>{await pool.query('INSERT INTO remote_input_audit(session_id,event_type,payload) VALUES ($1,$2,$3)',[sessionId,eventType,payload]);});
  });
