const billQ=new Queue('billing',{connection:redis});
export async function startBilling(userId:number,period:string){
  const r=await pool.query("INSERT INTO billing_runs(user_id,period,status) VALUES ($1,$2,'pending') ON CONFLICT (user_id,period) DO UPDATE SET status=billing_runs.status RETURNING id",[userId,period]);
  await billQ.add('charge',{runId:String(r.rows[0].id)});
}
export function startBillingWorker(){
  new Worker('billing',async(job:any)=>{
    const {runId}=job.data;const step=job.name;
    const r=(await pool.query('SELECT user_id,period,steps,charge_id FROM billing_runs WHERE id=$1',[runId])).rows[0];if(!r)return;
    const idem=`bill:${runId}:${step}`;
    if(r.steps[step]==='done')return; // idempotent skip
    await pool.query(`UPDATE billing_runs SET steps=jsonb_set(steps,$1::text[],'"running"',true) WHERE id=$2`,[`{${step}}`,runId]);
    io.of('/billing').to(`user:${r.user_id}`).emit('step',{runId:String(runId),step,status:'running'});
    try{
      let payload:any={};
      if(step==='charge')payload={chargeId:await stripeCharge(r.user_id,idem)};
      else if(step==='invoice')payload={invoiceId:await genPdf(runId,r.user_id)};
      else if(step==='email')await sendEmail(r.user_id,r.invoice_id);
      else if(step==='tax')await remitTax(r.user_id,r.period,idem);
      await pool.query(`UPDATE billing_runs SET steps=jsonb_set(steps,$1::text[],'"done"',true) ${payload.chargeId?", charge_id='"+payload.chargeId+"'":''} ${payload.invoiceId?", invoice_id='"+payload.invoiceId+"'":''} WHERE id=$2`,[`{${step}}`,runId]);
      io.of('/billing').to(`user:${r.user_id}`).emit('step',{runId:String(runId),step,status:'done'});
      const order=['charge','invoice','email','tax'];const idx=order.indexOf(step);
      if(idx<order.length-1)await billQ.add(order[idx+1],{runId});
      else{await pool.query("UPDATE billing_runs SET status='done' WHERE id=$1",[runId]);io.of('/billing').to(`user:${r.user_id}`).emit('done',{runId:String(runId)});}
    }catch(e:any){
      await pool.query(`UPDATE billing_runs SET steps=jsonb_set(steps,$1::text[],'"failed"',true) WHERE id=$2`,[`{${step}}`,runId]);
      throw e; // BullMQ retry
    }
  },{connection:redis,settings:{backoffStrategy:(attempts:number)=>Math.min(60000,2**attempts*1000)}});
}
