export async function submitResult(matchId:number,winnerSlot:number,adminId:number){
  const client=await pool.connect();
  try{await client.query('BEGIN');
    const m=await client.query('SELECT tournament_id,slot_a,slot_b,winner_slot,advances_to_slot FROM matches WHERE id=$1 FOR UPDATE',[matchId]);
    if(!m.rows[0])return {error:'no_match'};
    if(m.rows[0].winner_slot){await client.query('ROLLBACK');return {error:'already_resolved'};}
    if(winnerSlot!==m.rows[0].slot_a&&winnerSlot!==m.rows[0].slot_b){await client.query('ROLLBACK');return {error:'invalid_winner'};}
    await client.query('UPDATE matches SET winner_slot=$1,played_at=now() WHERE id=$2',[winnerSlot,matchId]);
    if(m.rows[0].advances_to_slot){
      const winnerTeam=await client.query('SELECT team_id FROM bracket_slots WHERE tournament_id=$1 AND slot_id=$2',[m.rows[0].tournament_id,winnerSlot]);
      await client.query('UPDATE bracket_slots SET team_id=$1,from_match_id=$2 WHERE tournament_id=$3 AND slot_id=$4',[winnerTeam.rows[0].team_id,matchId,m.rows[0].tournament_id,m.rows[0].advances_to_slot]);
    }
    await client.query('COMMIT');
    io.of('/tourney').to(`t:${m.rows[0].tournament_id}`).emit('bracket:update',{tournamentId:String(m.rows[0].tournament_id),matchId:String(matchId),winnerSlot});
