import {pool} from '../infra/pg';
import {Summary} from '../models/Summary';
import Anthropic from '@anthropic-ai/sdk';
import {io} from '../server';
const anth=new Anthropic();
export async function closeAndSummarize(chatId:number){
  await pool.query("UPDATE support_chats SET status='closed',closed_at=now() WHERE id=$1",[chatId]);
  const msgs=await pool.query('SELECT body FROM chat_messages WHERE chat_id=$1 ORDER BY id',[chatId]);
  const stream=await anth.messages.stream({model:'claude-opus-4-7',max_tokens:512,messages:[{role:'user',content:'Summarize:\n'+msgs.rows.map((m:any)=>m.body).join('\n')}]});
  let acc='';
  for await(const e of stream){if(e.type==='content_block_delta'&&e.delta.type==='text_delta'){acc+=e.delta.text;io.of('/supportChat').to(`chat:${chatId}`).emit('summary:token',{chatId:String(chatId),text:e.delta.text});}}
  const final=await stream.finalMessage();
  await Summary.create({_id:`s_${chatId}`,chatId:String(chatId),text:acc,llmTokens:final.usage.output_tokens,llmCostCents:Math.ceil(final.usage.output_tokens*0.001)});
  io.of('/supportChat').to(`chat:${chatId}`).emit('summary:done',{chatId:String(chatId),text:acc});
