import {pool} from '../infra/pg';
import {Queue,Worker} from 'bullmq';
import {redis} from '../infra/redis';
import {io} from '../server';
import crypto from 'crypto';
const erQ=new Queue('erasure',{connection:redis});
export async function requestErasure(userId:number){
  const r=await pool.query(`INSERT INTO erasure_requests(user_id) VALUES ($1) RETURNING id`,[userId]);
  await erQ.add('cascade',{requestId:String(r.rows[0].id),userId},{delay:30*86400*1000});
  io.of('/erasure').to(`user:${userId}`).emit('erasure:status',{requestId:String(r.rows[0].id),status:'pending'});
  return {requestId:String(r.rows[0].id)};
}
export function startErasureWorker(){
  new Worker('erasure',async(job:any)=>{
    const {requestId,userId}=job.data;
    const client=await pool.connect();
    try{await client.query('BEGIN');
      await client.query('DELETE FROM notifications WHERE user_id=$1',[userId]);
      await client.query('DELETE FROM notification_dispatches WHERE notification_id IN (SELECT id FROM notifications WHERE user_id=$1)',[userId]);
      await client.query('DELETE FROM mentions WHERE mentioned_user_id=$1',[userId]);
      const hash=crypto.createHash('sha256').update(String(userId)).digest('hex');
      await client.query(`INSERT INTO erasure_audit(user_id_hash,action) VALUES ($1,'erased')`,[hash]);
      await client.query(`UPDATE erasure_requests SET status='done',processed_at=now() WHERE id=$1`,[requestId]);
      await client.query('COMMIT');
    }catch(e){await client.query('ROLLBACK');throw e;}finally{client.release();}
  },{connection:redis});
}
export function registerErasureNamespace(nsp:any){
  nsp.use(authMw);
  nsp.on('connection',(socket:any)=>{socket.join(`user:${socket.data.user.id}`);});
}

