import {useEffect,useState,useCallback} from 'react';
import {io,Socket} from 'socket.io-client';
let sock:Socket|null=null;
function getSock(t:string){if(sock)return sock;sock=io('/cal',{auth:{token:t},transports:['websocket']});return sock;}
export function useCalendar(calendarId:string,t0:string,t1:string,token:string){
  const [events,setEvents]=useState<any[]>([]);
  useEffect(()=>{
    const s=getSock(token);
    const open=()=>s.emit('cal:open',{calendarId,t0,t1},(r:any)=>setEvents(r.events));
    const onR=(e:any)=>setEvents(p=>p.map(x=>String(x.id)===e.eventId?{...x,starts_at:e.newStart,ends_at:e.newEnd,version:e.version}:x));
    s.on('connect',open);s.on('event:rescheduled',onR);
    if(s.connected)open();
    return ()=>{s.off('connect',open);s.off('event:rescheduled',onR);};
  },[calendarId,t0,t1,token]);
  const reschedule=useCallback((eventId:string,newStart:string,newEnd:string,version:number)=>new Promise((res,rej)=>getSock(token).emit('event:reschedule',{eventId,newStart,newEnd,expectedVersion:version},(r:any)=>r.error?rej(r):res(r))),[token]);
  return {events,reschedule};
}

