import {pool} from '../infra/pg';
import {io} from '../server';
export async function ingestFlag(f:any){
  const sla=new Date(Date.now()+(f.amountCents>1000000?5*60_000:30*60_000));
  const r=await pool.query('INSERT INTO flagged_txn(txn_id,user_id,amount_cents,score,reason,sla_at) VALUES ($1,$2,$3,$4,$5,$6) RETURNING id',[f.txnId,f.userId,f.amountCents,f.score,f.reason,sla]);
  const queue=f.amountCents>1000000?'high':'normal';
  io.of('/fraud').to(`queue:${queue}`).emit('flagged',{id:String(r.rows[0].id),...f,slaAt:sla});
}
export function registerFraudNamespace(nsp:any){
  nsp.use(authMw);
  nsp.on('connection',(socket:any)=>{
    const uid=socket.data.user.id;
    socket.on('queue:subscribe',async({queue}:any,ack:any)=>{await socket.join(`queue:${queue}`);const r=await pool.query('SELECT * FROM flagged_txn WHERE decision IS NULL ORDER BY sla_at LIMIT 100');ack({items:r.rows});});
    socket.on('claim',async({id}:any,ack:any)=>{const r=await pool.query('UPDATE flagged_txn SET assigned_analyst=$1 WHERE id=$2 AND assigned_analyst IS NULL RETURNING *',[uid,id]);if(r.rowCount===0)return ack({error:'taken'});ack({item:r.rows[0]});});
    socket.on('decide',async({id,decision}:any,ack:any)=>{await pool.query('UPDATE flagged_txn SET decision=$1,decision_at=now() WHERE id=$2 AND assigned_analyst=$3',[decision,id,uid]);ack({ok:true});});
  });
}
// SLA watcher
import {setInterval as si} from 'timers';
si(async()=>{const r=await pool.query(`SELECT id,assigned_analyst FROM flagged_txn WHERE decision IS NULL AND sla_at <= now()`);for(const row of r.rows){const target=row.assigned_analyst?`analyst:${row.assigned_analyst}`:'queue:normal';io.of('/fraud').to(target).emit('sla:warn',{id:String(row.id)});}},10_000);

