import {useEffect,useState,useCallback} from 'react';
import {io,Socket} from 'socket.io-client';
let sock:Socket|null=null;
function getSock(t:string){if(sock)return sock;sock=io('/fraud',{auth:{token:t},transports:['websocket']});return sock;}
export function useFraudQueue(queue:'high'|'normal',token:string){
  const [items,setItems]=useState<any[]>([]);
  useEffect(()=>{
    const s=getSock(token);
    const sub=()=>s.emit('queue:subscribe',{queue},(r:any)=>setItems(r.items));
    const onF=(f:any)=>setItems(p=>[f,...p]);
    s.on('connect',sub);s.on('flagged',onF);
    if(s.connected)sub();
    return ()=>{s.off('connect',sub);s.off('flagged',onF);};
  },[queue,token]);
  const claim=useCallback((id:string)=>new Promise((res,rej)=>getSock(token).emit('claim',{id},(r:any)=>r.error?rej(r):res(r))),[token]);
  const decide=useCallback((id:string,decision:string)=>new Promise((res)=>getSock(token).emit('decide',{id,decision},res)),[token]);
  return {items,claim,decide};
}

