import {StreamComment} from '../models/StreamComment';
import {io} from '../server';
import {filterSpam} from '../infra/spam';
import {redis} from '../infra/redis';
export function registerShopNamespace(nsp:any){
  nsp.use(authMw);
  nsp.on('connection',(socket:any)=>{
    const uid=socket.data.user.id;
    socket.on('stream:join',async({streamId}:any,ack:any)=>{await socket.join(`stream:${streamId}`);ack({ok:true});});
    socket.on('comment:send',async({streamId,body}:any,ack:any)=>{const k=`shop:rl:${uid}:${streamId}`;const n=await redis.incr(k);if(n===1)await redis.expire(k,1);if(n>5)return ack({error:'rate_limited'});if(filterSpam(body))return ack({error:'spam'});const c=await StreamComment.create({streamId,viewerId:String(uid),body});io.of('/shop').to(`stream:${streamId}`).emit('comment',c.toObject());ack({ok:true});});
    socket.on('comment:pin',async({streamId,commentId}:any,ack:any)=>{if(socket.data.user.role!=='host')return ack({error:'forbidden'});await StreamComment.updateOne({_id:commentId},{$set:{pinnedAt:new Date()}});io.of('/shop').to(`stream:${streamId}`).emit('pinned',{commentId});ack({ok:true});});
  });
}

