import {useEffect,useState,useCallback} from 'react';
import {io,Socket} from 'socket.io-client';
let sock:Socket|null=null;
function getSock(t:string){if(sock)return sock;sock=io('/shop',{auth:{token:t},transports:['websocket']});return sock;}
export function useLiveShop(streamId:string,token:string){
  const [comments,setC]=useState<any[]>([]);
  const [pinned,setP]=useState<string|null>(null);
  useEffect(()=>{
    const s=getSock(token);
    const join=()=>s.emit('stream:join',{streamId},()=>{});
    const onC=(c:any)=>{if(c.streamId===streamId)setC(p=>[...p.slice(-300),c]);};
    const onP=({commentId}:any)=>setP(commentId);
    s.on('connect',join);s.on('comment',onC);s.on('pinned',onP);
    if(s.connected)join();
    return ()=>{s.off('connect',join);s.off('comment',onC);s.off('pinned',onP);};
  },[streamId,token]);
  const send=useCallback((body:string)=>new Promise((res,rej)=>getSock(token).emit('comment:send',{streamId,body},(r:any)=>r.error?rej(r):res(r))),[streamId,token]);
  return {comments,pinned,send};
}

