import {PlayerState} from '../models/PlayerState';
import {pool} from '../infra/pg';
import {io} from '../server';
import mongoose from 'mongoose';
export async function requestHandoff(playerId:string,fromZone:string,toZone:string){
  const session=await mongoose.startSession();
  try{
    let result:any;
    await session.withTransaction(async()=>{
      const p=await PlayerState.findOneAndUpdate({_id:playerId,zoneId:fromZone,'handoffPending.toZone':{$exists:false}},{$set:{handoffPending:{toZone,startedAt:new Date()}}},{new:true,session});
      if(!p){result={error:'already_in_handoff'};return;}
      // check dest capacity
      const z=await pool.query('UPDATE zones SET current_players=current_players+1 WHERE id=$1 AND current_players<capacity RETURNING id',[toZone]);
      if(z.rowCount===0){await PlayerState.updateOne({_id:playerId},{$unset:{handoffPending:1}},{session});result={error:'dest_full'};return;}
      result={ok:true,playerState:p};
    });
    return result;
  }finally{await session.endSession();}
}
export async function completeHandoff(playerId:string,toZone:string){
  const p=await PlayerState.findOneAndUpdate({_id:playerId,'handoffPending.toZone':toZone},{$set:{zoneId:toZone},$unset:{handoffPending:1}},{new:true});
  if(!p)return {error:'no_pending'};
  await pool.query('UPDATE zones SET current_players=current_players-1 WHERE id=(SELECT zone_id FROM (SELECT $1::text AS zone_id) z)',[p.zoneId]); // simplified
  await pool.query("INSERT INTO handoffs(player_id,to_zone,completed_at) VALUES ($1,$2,now())",[playerId,toZone]);
  io.of('/mmo').to(`zone:${toZone}`).emit('handoff:complete',{playerId});
  return {ok:true};
}
export function registerMmoNamespace(nsp:any){
  nsp.use(authMw);
  nsp.on('connection',(socket:any)=>{
    const playerId=String(socket.data.user.id);
    socket.on('zone:enter',async({zoneId}:any,ack:any)=>{await socket.join(`zone:${zoneId}`);const p=await PlayerState.findById(playerId).lean();ack({state:p});});
    socket.on('handoff:request',async({fromZone,toZone}:any,ack:any)=>{const r=await requestHandoff(playerId,fromZone,toZone);ack(r);});
    socket.on('handoff:accept',async({toZone}:any,ack:any)=>{const r=await completeHandoff(playerId,toZone);ack(r);});
    socket.on('position',async({x,y}:any)=>{await PlayerState.updateOne({_id:playerId},{$set:{x,y,updatedAt:new Date()}});const p=await PlayerState.findById(playerId).lean();if(p)socket.to(`zone:${p.zoneId}`).emit('player:moved',{playerId,x,y});});
  });
}

