import {useEffect,useState,useCallback} from 'react';
import {io,Socket} from 'socket.io-client';
let sock:Socket|null=null;
function getSock(t:string){if(sock)return sock;sock=io('/mmo',{auth:{token:t},transports:['websocket'],reconnection:true});return sock;}
export function useMmoZone(token:string){
  const [state,setState]=useState<any>(null);
  useEffect(()=>{
    const s=getSock(token);
    s.on('handoff:complete',({playerId}:any)=>{setState((st:any)=>st?{...st,zoneId:st.handoffPending?.toZone}:st);});
    return ()=>{s.off('handoff:complete');};
  },[token]);
  const enter=useCallback((zoneId:string)=>new Promise((res)=>getSock(token).emit('zone:enter',{zoneId},(r:any)=>{setState(r.state);res(r);})),[token]);
  const handoff=useCallback(async(fromZone:string,toZone:string)=>{const r:any=await new Promise(res=>getSock(token).emit('handoff:request',{fromZone,toZone},res));if(r.error)return r;const c:any=await new Promise(res=>getSock(token).emit('handoff:accept',{toZone},res));return c;},[token]);
  return {state,enter,handoff};
}
